import { useEffect, useState } from 'react';
import api from '../api/axios';

function Dashboard() {
  const [analytics, setAnalytics] = useState({ totalUsers: 0 });
  const [videos, setVideos] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [analyticsRes, videosRes] = await Promise.all([
          api.get('/users/analytics'),
          api.get('/videos')
        ]);

        setAnalytics(analyticsRes.data);
        setVideos(videosRes.data);
      } catch (_error) {
        setAnalytics({ totalUsers: 0 });
        setVideos([]);
      }
    };

    fetchData();
  }, []);

  return (
    <div>
      <h4 className="mb-3">Admin Dashboard</h4>
      <div className="row g-3 mb-3">
        <div className="col-md-4">
          <div className="card">
            <div className="card-body">
              <h6 className="text-muted">Total Users</h6>
              <h3>{analytics.totalUsers}</h3>
            </div>
          </div>
        </div>
        <div className="col-md-4">
          <div className="card">
            <div className="card-body">
              <h6 className="text-muted">Total Videos</h6>
              <h3>{videos.length}</h3>
            </div>
          </div>
        </div>
        <div className="col-md-4">
          <div className="card">
            <div className="card-body">
              <h6 className="text-muted">Total Views</h6>
              <h3>{videos.reduce((sum, video) => sum + (video.views || 0), 0)}</h3>
            </div>
          </div>
        </div>
      </div>

      <div className="card">
        <div className="card-body">
          <h6 className="mb-3">Recent Videos</h6>
          {videos.slice(0, 10).map((video) => (
            <div className="d-flex justify-content-between border-bottom py-2" key={video._id}>
              <span>{video.title}</span>
              <small className="text-muted">{video.views || 0} views</small>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
